#!/usr/bin/env python3
"""Generate deterministic L++ sources for compiler scalability measurements."""
from __future__ import annotations

import argparse
from pathlib import Path

TARGETS = (10_000, 50_000, 100_000)


def generate(lines: int) -> str:
    if lines < 5:
        raise ValueError("need at least five lines")
    body_count = lines - 4
    out = [
        "# Generated by benchmarks/scalability/generate.py",
        "def main():",
        "    mut acc := 0",
    ]
    out.extend("    acc = acc + 1" for _ in range(body_count))
    out.append("    print(acc)")
    return "\n".join(out) + "\n"


def main() -> None:
    parser = argparse.ArgumentParser()
    parser.add_argument("--out", type=Path, default=Path(__file__).with_name("generated"))
    parser.add_argument("--lines", type=int, nargs="*", default=list(TARGETS))
    args = parser.parse_args()
    args.out.mkdir(parents=True, exist_ok=True)
    for lines in args.lines:
        path = args.out / f"scale_{lines}.lpp"
        path.write_text(generate(lines))
        print(f"wrote {path} ({lines} lines)")


if __name__ == "__main__":
    main()
